/**
 * Executes a shell command synchronously and logs output. Exits process on failure.
 * @param {string} command The shell command to execute.
 * @param {string} errorMessage Message to display if the command fails.
 */
function runCommand(command, errorMessage) {
  try {
    console.log(`Executing: ${command}`);
    execSync(command, { stdio: 'inherit', cwd: projectRoot });
  } catch (error) {
    console.error(`ERROR: ${errorMessage}\nDetails: ${error.message}`);
    process.exit(1); // Exit with a non-zero code to indicate failure
  }
}

/**
 * Downloads a file from a URL to a specified destination. Exits process on failure.
 * @param {string} url The URL of the file to download.
 * @param {string} destinationPath The absolute path where the file should be saved.
 */
function downloadFile(url, destinationPath) {
  const fileName = path.basename(destinationPath);
  console.log(`Downloading "${fileName}" from "${url}"...`);
  try {
    // Using curl -fsSL for silent, fail-fast, follow redirects. Assumes curl is available.
    execSync(`curl -fsSL "${url}" -o "${destinationPath}"`, { stdio: 'inherit', cwd: projectRoot });
    console.log(`Successfully downloaded "${fileName}".`);
  } catch (error) {
    console.error(`ERROR: Failed to download "${fileName}". Please check the URL or your network connection.`);
    console.error(`Details: ${error.message}`);
    process.exit(1);
  }
}

